import {Asset} from './AssetLoad';

// Single cache bucket
export type Cache = {[id:string]: CacheItem};
export type Caches = {[id:string]: Cache};

/**
 * Internal class to represent a cached item
 * Saves a reference to the original URL request
 * and the content.
 * @private
 * @class CacheItem
 * @memberof jibo.loader
 * @param {String} request Full path requested
 * @param {any} content Result of the load.
 */
export class CacheItem
{
    constructor(public request:string, public content:any)
    {
    }

    /**
     * Destroy the content, don't use after this.
     * @method jibo.loader.CacheItem#destroy
     * @private
     */
    destroy():void
    {
        // Destroy any objects with a destroy function
        if (this.content.destroy)
        {
            this.content.destroy();
        }

        // Clear images if we have an HTML node
        if (this.content.tagName === 'IMG')
        {
            this.content.src = '';
        }
        this.content = null;
        this.request = null;
    }

}

/**
 * Manages a cache for assets.
 * @class AssetCache
 * @memberof jibo.loader
 */
class AssetCache
{
    /**
     * The name of the default protected cache.
     * @type {String}
     * @name jibo.loader.AssetCache.DEFAULT_CACHE
     * @readOnly
     */
    public static DEFAULT_CACHE:string = 'default';

    private _cacheId:string;
    private _cache:Cache;
    private _cachesMap:Caches;

    constructor()
    {
        /**
         * The cache containing assets.
         * @type {Object}
         * @name jibo.loader.AssetCache#_cache
         * @private
         */
        this._cache = null;

        /**
         * A map of the current caches
         * @type {Object}
         * @name jibo.loader.AssetCache#_cachesMap
         * @private
         */
        this._cachesMap = {};

        // Select the default cache
        this.addCache(AssetCache.DEFAULT_CACHE);
    }

    /**
     * Add another cache and auto-select it.
     * @method jibo.loader.AssetCache#addCache
     * @param {String} id The cache id to add.
     */
    addCache(id:string): void
    {
        if (this._cachesMap[id])
        {
            throw new Error(`AssetCache: cache alread exists : '${id}'`);
        }
        this._cachesMap[id] = {};
        this.activeCache = id;
    }

    /**
     * Get all the caches.
     * @method jibo.loader.AssetCache#getCaches
     * @internal
     * @return {Object} Map of caches by cache ID.
     */
    getCaches(): Caches
    {
        return this._cachesMap;
    }

    /**
     * Set or get the currently active cache.
     * @name jibo.loader.AssetCache#activeCache
     * @type {String}
     */
    set activeCache(id:string)
    {
        const cache:Cache = this._cachesMap[id];
        if (!cache)
        {
            throw new Error(`AssetCache: unable to find cache: '${id}'`);
        }
        this._cache = cache;
        this._cacheId = id;
    }
    get activeCache(): string
    {
        return this._cacheId;
    }

    /**
     * Remove a cache by id
     * @method jibo.loader.AssetCache#deleteCache
     * @param {String} id The cache id to unload/remove.
     * @param {String} [select='default'] The cache to redirect to if removing the current cache
     */
    deleteCache(id:string, select:string=AssetCache.DEFAULT_CACHE): void
    {
        const cache:Cache = this._cachesMap[id];
        if (!cache)
        {
            console.warn(`AssetCache: unable to remove cache: '${id}'`);
        }
        else
        {
            const active:string = this._cacheId;

            // Remove everything from the current cache
            this.empty(id);

            // Delete from the map
            delete this._cachesMap[id];

            // We're deleting the current cache, set to default
            if (select && id === active)
            {
                this.activeCache = select;
            }
        }
    }

    /**
     * Retrieves a single asset from the cache.
     * @method jibo.loader.AssetCache#read
     * @param {String} id The asset to get.
     * @param {String} [cacheId] Optional cache ID to specify.
     * @return {any} Result or null, if no asset
     */
    read(id:string, cacheId?:string): any
    {
        const cache:Cache = this.getCache(cacheId);
        if (!cache)
        {
            throw new Error(`AssetCache: unable to find cache: '${cacheId}'`);
        }
        return !!cache[id] ? cache[id].content : null;
    }

    /**
     * Adds a single asset to the cache.
     * @method jibo.loader.AssetCache#write
     * @param {String} id The id to save the asset as.
     * @param {String} request The URL or URI requested.
     * @param {*} content The asset content to save.
     */
    write(id:string, request:string, content:any, cacheId?:string): void
    {
        const cache:Cache = this.getCache(cacheId);
        const cacheItem:CacheItem = cache[id];
        if (cacheItem)
        {
            if(cacheItem.request === request)
            {
                // If matching id and request found in cache, do not delete and replace
                return;
            }
            else
            {
                // Fail on attempts to loading an asset with a different resource path but same id as an already loaded asset in given cache
                throw new Error(`AssetCache: cannot load an asset with a different resource path but same id as an asset already in cache.`
                + ` Attempted asset using id: '${id}' request: '${request}' cache: '${cacheId}'`);
            }
        }
        cache[id] = new CacheItem(request, content);
    }

    /**
     * Get a cache by id.
     * @method jibo.loader.AssetCache#getCache
     * @internal
     * @param {String} [cacheId] The id to save the asset as.
     * @return {Cache} The cache by id, or the active cache.
     */
    getCache(cacheId?:string): Cache
    {
        return cacheId ? this._cachesMap[cacheId] : this._cache;
    }

    /**
     * Removes a single asset from the cache.
     * @method jibo.loader.AssetCache#delete
     * @param {Object|String} asset The asset to remove.
     */
    delete(asset:Asset|string, cacheId?:string): void
    {
        const cache:Cache = this.getCache(cacheId);
        let id:string = typeof asset === 'string' ? <string>asset : (<Asset>asset).id;

        // If we don't have an ID, stop
        if (!id)
        {
            return;
        }

        const item:CacheItem = cache[id];
        if (item)
        {
            item.destroy();
            delete cache[id];
        }
    }

    /**
     * Removes all assets from the cache.
     * @method jibo.loader.AssetCache#empty
     * @param {string} [cacheId] The optional cache
     */
    empty(cacheId?:string): void
    {
        const cache:Cache = this.getCache(cacheId);
        for (let id in cache)
        {
            this.delete(id);
        }
    }

    /**
     * Destroys the cache. Don't use after this.
     * @method jibo.loader.AssetCache#destroy
     */
    destroy(): void
    {
        for (let id in this._cachesMap)
        {
            this.deleteCache(id, null);
        }
        this._cache = null;
    }
}

export default AssetCache;
