import LoaderError from '../errors/LoaderError';
import Callback from '../LoaderCallback';
import path = require('path');

export module FILETYPE {
    export const IMAGE = 'image';
    export const BINARY = 'binary';
    export const JSON = 'json';
    export const XML = 'xml';
    export const CSS = 'css';
    export const JAVASCRIPT = 'js';
    export const SVG = 'svg';
    export const TEXT = 'text';
    export const HTML = 'html';
}

/**
 * Loads all assets to a skill,
 * including images, data, code. AbstractLoader supports cache-busting
 * in the browser using dynamic query string parameters.
 * @class AbstractLoader
 * @memberof jibo.loader
 */
abstract class AbstractLoader {

    /**
     * Prepare the URI request to be absolute.
     * @method jibo.loader.AbstractLoader#prepare
     * @param {String} uri The relative or absolute file to load.
     * @return {String} The absolute URI.
     */
    public prepare(url:string):string
    {
        return url;
    }

    /**
     * Loads the asset file.
     * @method jibo.loader.AbstractLoader#load
     * @param {String} uri The file to load.
     * @param {Function} callback Callback when complete.
     * @param {Object} [options] Optional load options
     * @param {String} [options.format] Force a format type, either:
     *        "image", "json", "xml", "css", "js", "svg", "text", or "html"
     */
    public load(uri:string, callback:Callback, options?:any): void
    {
        // Check for override format
        let type:string = this.getFileType(uri);
        if (options && options.format) {
            type = options.format;
        }
        this.internalLoad(type, uri, callback, options);
    }

    /**
     * Get a mime type by uri.
     * @method jibo.loader.AbstractLoader#internalLoad
     * @protected
     * @param {String} type The named type of file.
     * @param {String} uri The file uri.
     * @param {String} encoding The readFile encoding type.
     * @param {Function} callback Callback for the method.
     */
    protected internalLoad(type:string, uri:string, callback:Callback, options?:any): void
    {
        // must override
    }

    /**
     * Create new LoaderError.
     * @method jibo.loader.AbstractLoader#createError
     * @private
     * @param {Error} err The original error.
     * @param {String} uri The file URL to load.
     * @param {String} [message] The optional message.
     * @return {jibo.loader.LoaderError} The new error.
     */
    protected createError(err:any, uri:string, message?:string): LoaderError
    {
        return new LoaderError(typeof err === 'string' ? new Error(err) : err, uri, message);
    }

    /**
     * Standard internal post-process for loading.
     * @method jibo.loader.AbstractLoader#internalDone
     * @protected
     * @param {String} type The named type of file
     * @param {String} uri The file uri.
     * @param {String} data The result data.
     * @param {Function} callback Callback for the method.
     */
    protected internalDone(type:string, uri:string, data:string, callback:Callback): void
    {
        switch(type) {
            case FILETYPE.SVG:
                this.parseDOM('image/svg+xml', uri, data, callback);
                break;
            case FILETYPE.XML:
                this.parseDOM('application/xml', uri, data, callback);
                break;
            case FILETYPE.HTML:
                this.parseDOM('text/html', uri, data, callback);
                break;
            case FILETYPE.CSS:
                this.parseStyle(data, callback);
                break;
            case FILETYPE.JSON:
                this.parseJSON(uri, data, callback);
                break;
            default:
                callback(null, data);
                break;
        }
    }

    /**
     * Loads XML or SVG elements.
     * @method jibo.loader.AbstractLoader#loadDOM
     * @private
     * @param {String} type The file type to parse DOM.
     * @param {String} uri The file to load.
     * @param {Function} callback Callback when complete.
     */
    private parseDOM(parseType:string, uri:string, data:string, callback:Callback): void
    {
        try
        {
            const parser = new DOMParser();
            const object = parser.parseFromString(data, parseType);
            callback(null, object);
        }
        catch(e)
        {
            callback(this.createError(e, uri));
        }
    }

    /**
     * Loads CSS element and return HTMLStyleElement.
     * @method jibo.loader.AbstractLoader#loadStyle
     * @private
     * @param {String} uri The file to load.
     * @param {String} type The file type to parse DOM.
     * @param {Function} callback Callback when complete.
     */
    private parseStyle(data:any, callback:Callback): void
    {
        const style = document.createElement('style');
        style.type = 'text/css';
        style.innerHTML = data;
        callback(null, style);
    }

    /**
     * Loads a JSON file.
     * @method jibo.loader.AbstractLoader#loadJSON
     * @private
     * @param {String} uri The file to load.
     * @param {Function} callback Callback when complete.
     */
    private parseJSON(uri:string, data:any, callback:Callback):void
    {
        try
        {
            data = JSON.parse(data);
        }
        catch(e)
        {
            return callback(this.createError(e, uri, 'Failed to parse JSON'));
        }
        callback(null, data);
    }


    /**
     * Gets a file type by uri.
     * @method jibo.loader.AbstractLoader#getFileType
     * @private
     * @param {String} uri The file uri.
     * @return {String} The filetype.
     */
    private getFileType(uri:string): string
    {
        const extension = path.extname(uri).toLowerCase();
        switch (extension) {
            case '.jpeg':
            case '.jpg':
            case '.gif':
            case '.png':
            case '.webp':
            case '.bmp':
                return FILETYPE.IMAGE;
            case '.json':
            case '.keys':
            case '.bt':
                return FILETYPE.JSON;
            case '.xml':
                return FILETYPE.XML;
            case '.css':
                return FILETYPE.CSS;
            case '.js':
                return FILETYPE.JAVASCRIPT;
            case '.svg':
                return FILETYPE.SVG;
            case '.xml':
                return FILETYPE.XML;
            case '.html':
            case '.htm':
            case '.xhtml':
                return FILETYPE.HTML;
            default:
                return FILETYPE.TEXT;
        }
    }
}
export default AbstractLoader;
