import Task from './Task';
import Callback from '../LoaderCallback';
import AssetManager from '../AssetManager';

/**
 * Internal class for dealing with async load assets through Loader.
 * ```
 * jibo.loader.load({
 *    src: "data.json"
 * }, (err, data) => {});
 * ```
 * @class LoadTask
 * @extends jibo.loader.Task
 * @memberof jibo.loader
 * @internal
 * @param {jibo.loader.AssetManager} manager Instance of AssetManager.
 * @param {Object} asset The data properties.
 * @param {String} asset.src The source.
 * @param {String} [asset.format] Force a format for external requests.
 * @param {Boolean} [asset.remote=false] `true` to force a remote download over XMLHttpRequest.
 * @param {String} [asset.format] Force a format type, either:
 *        "image", "json", "xml", "css", "js", "svg", "text", or "html"
 * @param {Number} [asset.timeout=0] Number of milliseconds for remote load to timeout.
 * @param {Boolean|String} [asset.cache=false] `true` to cache the result. String to add to a specific cache.
 * @param {String} [asset.id] ID of asset.
 * @param {Function} [asset.complete] The function to call when done.
 */
class LoadTask extends Task
{
    static priority:number;
    public src:string;

    /**
     * Tests if this task should be run.
     * @method jibo.loader.LoadTask.test
     * @static
     * @param {Object} asset The asset to check.
     * @return {Boolean} `true` if the asset is compatible with this asset.
     */
    static test(asset:any):boolean
    {
        return !!asset.src;
    }

    constructor(manager:AssetManager, asset:any)
    {
        super(manager, asset, asset.src);

        /**
         * The source URL to load.
         * @property {String} src
         */
        this.src = this.prepare(asset.src);
    }

    /**
     * Starts the task.
     * @method  jibo.loader.LoadTask#start
     * @param  {jibo.loader.Task~completeCallback} callback Callback when finished.
     */
    start(callback:Callback): void
    {
        this.simpleLoad(this.src, callback, {
            remote: this.remote,
            timeout: this.timeout,
            format: this.format
        });
    }
}

export default LoadTask;
