import AssetManager from '../AssetManager';
import Callback from '../LoaderCallback';
import path = require('path');
import {Asset, default as AssetLoad} from '../AssetLoad';

// Callback when finished loading
export declare type Complete = (err:Error, result:any, originalAsset?:Asset, assets?:Array<Asset>) => void;

/**
 * Executes when the task starts.
 * @callback jibo.loader.Task~startCallback
 * @param {Error} error The error thrown by task.
 * @param {*} result The final result of task loading.
 */

/**
 * Executes when the task is complete.
 * @callback jibo.loader.Task~completeCallback
 * @param {Error} error The error, if any, thrown by loading.
 * @param {*} result The result of load.
 * @param {Object} originalAsset The original asset object.
 * @param {Array} additionalAsset An Array to add additional assets.
 */

/**
 * Single asynchronous task.
 * @class Task
 * @internal
 * @memberof jibo.loader
 * @param {jibo.loader.AssetManager} manager Reference to the AssetManager instance.
 * @param {Object} asset The asset data.
 * @param {String} [asset.id=null] The task ID.
 * @param {Boolean} [asset.remote=false] `true` to force a remote download over XMLHttpRequest.
 * @param {Number} [asset.timeout=0] Number of milliseconds for remote load to timeout.
 * @param {String} [asset.format] Force a format type, either:
 *        "image", "json", "xml", "css", "js", "svg", "text", or "html"
 * @param {Boolean|String} [asset.cache=false] `true` to cache the result. String to add to a specific cache.
 * @param {jibo.loader.Task~completeCallback} [asset.complete=null] Call when complete.
 * @param {String} [fallbackId] The ID to set if no ID is explicitly set.
 *      This can be used for caching something that has no id.
 */
abstract class Task
{
    /**
     * Status for when task is waiting to be run.
     * @name jibo.loader.Task.WAITING
     * @type {int}
     * @static
     * @readOnly
     * @final
     * @default 0
     */
    static WAITING:number = 0;

    /**
     * Status for when task is currently being run.
     * @name jibo.loader.Task.RUNNING
     * @type {int}
     * @static
     * @readOnly
     * @final
     * @default 1
     */
    static RUNNING:number = 1;

    /**
     * Status for when task is finished.
     * @name jibo.loader.Task.FINISHED
     * @type {int}
     * @static
     * @readOnly
     * @final
     * @default 2
     */
    static FINISHED:number = 2;

    public status:number;
    public complete:Complete;
    public cache:boolean|string;
    public id:string;
    public original:any;
    public remote:boolean;
    public timeout:number;
    public format:string;

    /**
     * Internal class for dealing with async load assets.
     */
    constructor(public manager:AssetManager, asset:Asset, fallbackId?:string)
    {
        /**
         * The current status of the task.
         * @property {int} status 0 = waiting, 1 = running, 2 = finished.
         * @name jibo.loader.Task#status
         * @default 0
         */
        this.status = Task.WAITING;

        /**
         * The user call to fire when completed. Returns the arguments
         * result, originalAsset, and additionalAsset.
         * @type {jibo.loader.Task~completeCallback}
         * @name jibo.loader.Task#complete
         * @default null
         * @readOnly
         */
        this.complete = asset.complete || null;

        /**
         * `true` to cache the load and use later. String for specific named cache.
         * @type {Boolean|String}
         * @name jibo.loader.Task#cache
         * @default false
         * @readOnly
         */
        this.cache = asset.cache === undefined ? false : asset.cache;

        /**
         * The task id.
         * @type {String}
         * @name jibo.loader.Task#id
         */
        this.id = asset.id || null;

        /**
         * `true` to load asset remotely using http(s), `false` for auto-detect remote loading.
         * @type {Boolean|String}
         * @name jibo.loader.Task#remote
         * @default false
         * @readOnly
         */
        this.remote = asset.remote === undefined ? false : asset.remote;

        /**
         * The number of seconds to timeout remote loads.
         * @property {Number} timeout
         * @default 0
         */
        this.timeout = asset.timeout || 0;

        /**
         * Override the parsing format for the loader.
         * @property {String} format
         * @default 0
         */
        this.format = asset.format || null;

        /**
         * Reference to the original asset data.
         * @type {Object}
         * @name jibo.loader.Task#original
         * @readOnly
         */
        this.original = asset;

        // We're trying to cache but we don't have an ID
        if (this.cache && !this.id)
        {
            if (fallbackId && typeof fallbackId === "string")
            {
                // Get the base file name, without extension
                asset.id = this.id = path.parse(fallbackId).name;
            }

            // Check for ID if we're caching
            if (!this.id)
            {
                console.error("Caching an asset requires an id, none set", asset);
                this.cache = false;
            }
        }
    }

    /**
     * Starts the task.
     * @method  jibo.loader.Task#start
     * @param  {jibo.loader.Task~startCallback} callback Callback when finished.
     */
    public start(callback:Callback)
    {
        // callback must be: callback(err, result);
    }

    /**
     * Pass-through to the application load method.
     * @method jibo.loader.Task#load
     * @protected
     * @param {String|Array|Object} source The source to load.
     * @param {Object|Function} [options] The load options or callback function.
     */
    public load(source:any, options:any):AssetLoad
    {
        if (typeof options === "function")
        {
            options = { complete: options };
        }
        return this.manager.load(source, options);
    }

    /**
     * Pass-through to the application Loader.load.
     * @method jibo.loader.Task#simpleLoad
     * @protected
     * @param {String} url Path to file to load.
     * @param {Function} complete The callback.
     * @param {Object} [options]
     * @param {Boolean} [options.remote] `true` to force remote loading.
     * @param {Number} [options.timeout] Number of milliseconds before remote call does timeout.
     */
    public simpleLoad(url:string, complete:Callback, options?:any): void
    {
        this.manager.simpleLoad(url, complete, options || {
            remote: this.remote,
            timeout: this.timeout,
            format: this.format
        });
    }

    /**
     * Convert URI requests to absolute and handle asset packs.
     * @method jibo.loader.Task#prepare
     * @protected
     * @param {String} url Path to file to load.
     * @return {String} The absolute URI.
     */
    public prepare(uri:string): string
    {
        return this.manager.prepare(uri, this.remote);
    }

    /**
     * Destroys this and discards.
     * @method jibo.loader.Task#destroy
     */
    public destroy()
    {
        this.manager = null;
        this.status = Task.FINISHED;
        this.id = null;
        this.complete = null;
        this.original = null;
    }
}

export default Task;
