import http = require('http');
import Resource from './Resource';

/**
 * Request a Buffer using node's http module
 * @private
 * @class BinaryResource
 * @extends Resource
 * @param {String} type The load type
 * @param {String} url Full URL
 * @param {Function} callback when complete
 * @param {Object} [options] Optional options
 */
class BinaryResource extends Resource {

    public start() {
        http.get(this.url, (res) => {
            const data = [];
            res.on('data', (chunk) => {
                data.push(chunk);
            }).on('end', () => {
                this.result = Buffer.concat(data);
                this.complete();
            }).on('error', (e) => {
                this.complete(e);
            });
        });
    }

}

export default BinaryResource;