import Callback from '../../LoaderCallback';
import Resource from './Resource';

// some status constants
const STATUS_NONE = 0;
const STATUS_OK = 200;
const STATUS_EMPTY = 204;

/**
 * Request a Text using XMLHttpRequest
 * @private
 * @class TextResource
 * @extends Resource
 * @param {String} type The load type
 * @param {String} url Full URL
 * @param {Function} callback when complete
 * @param {Object} [options] Optional options
 */
class TextResource extends Resource {

    public request:XMLHttpRequest;

    constructor(type:string, url:string, callback:Callback, options?:any) {

        super(type, url, callback, options);

        this.onError = this.onError.bind(this);
        this.onAbort = this.onAbort.bind(this);
        this.onLoad = this.onLoad.bind(this);
        this.onTimeout = this.onTimeout.bind(this);

        const request:XMLHttpRequest = new XMLHttpRequest();
        request.responseType = 'text';
        options = options || {};
        if (options.timeout) {
            request.timeout = options.timeout;
            request.addEventListener('timeout', this.onTimeout, false);
        }
        request.addEventListener('error', this.onError, false);
        request.addEventListener('abort', this.onAbort, false);
        request.addEventListener('load', this.onLoad, false);
        this.request = request;
    }

    /**
     * Start the load.
     */
    public start(): void {
        this.request.open('GET', this.url, true);
        this.request.send();
    }

    /**
     * Destroy and don't use after calling.
     * @protected
     */
    protected destroy(): void {
        super.destroy();
        if (this.request) {
            this.request.removeEventListener('error', this.onError);
            this.request.removeEventListener('abort', this.onAbort);
            this.request.removeEventListener('load', this.onLoad);
            this.request.removeEventListener('timeout', this.onTimeout);
        }
        this.onError = null;
        this.onAbort = null;
        this.onLoad = null;
        this.onTimeout = null;
        this.request = null;
    }

    /**
     * Called when data successfully loads from an XHR request.
     * @private
     */
    private onLoad() {
        const request = this.request;
        const status = request.status;

        // status can be 0 when using the file:// protocol, also check if a response was found
        if (status === STATUS_OK || status === STATUS_EMPTY || (status === STATUS_NONE && request.responseText.length > 0)) {
            this.result = request.response || request.responseText;
        }
        else {
            return this.complete('[' + request.status + ']' + request.statusText + ':' + (<any>request).responseURL);
        }
        this.complete();
    }

    /**
     * Called if an error event fires for request
     * @private
     */
    private onError() {
        this.complete(this.reqType() + ' Request failed. '
            + 'Status: ' + this.request.status + ', text: "' + this.request.statusText + '"'
        );
    }

    /**
     * Called if an abort event fires for request.
     * @private
     */
    private onAbort() {
        this.complete(this.reqType() + ' Request was aborted by the user.');
    }

    /**
     * Quick helper to get string request type.
     * @private
     * @return {string} The type.
     */
    private reqType():string {
        return this.request.toString().replace('object ', '');
    }
}

export default TextResource;
