import Callback from '../../LoaderCallback';
import Resource from './Resource';

/**
 * Request a image using <img> tag
 * @private
 * @class ImageResource
 * @extends Resource
 * @param {String} type The load type
 * @param {String} url Full URL
 * @param {Function} callback when complete
 * @param {Object} [options] Optional options
 */
class ImageResource extends Resource {

    public result:HTMLImageElement;
    public timeoutId:any;

    constructor(type:string, url:string, callback:Callback, options?:any) {

        super(type, url, callback, options);

        this.onError = this.onError.bind(this);
        this.onLoad = this.onLoad.bind(this);
        this.onTimeout = this.onTimeout.bind(this);

        const result:HTMLImageElement = this.result = new Image();
        options = options || {};

        if (options.crossOrigin) {
            result.crossOrigin = options.crossOrigin;
        }
        
        result.addEventListener('error', this.onError, false);
        result.addEventListener('load', this.onLoad, false);

        if (options.timeout) {
            this.timeoutId = setTimeout(this.onTimeout, options.timeout);
        }
    }

    /**
     * Don't use after this
     * @private
     */
    protected destroy(): void {
        if (this.timeoutId) {
            clearTimeout(this.timeoutId);
            this.timeoutId = null;
        }
        if (this.result) {
            this.result.removeEventListener('error', this.onError);
            this.result.removeEventListener('load', this.onLoad);
        }
        this.onError = null;
        this.onLoad = null;
        this.onTimeout = null;
        this.result = null;
        super.destroy();
    }

    /**
     * Begin the load
     * @private
     */
    public start(): void {
        this.result.src = this.url;
    }

    /**
     * Called if a load errors out.
     * @private
     */
    private onError() {
        this.complete('Failed to load element using <IMG>');
    }

    /**
     * Called if an abort event fires for request.
     * @private
     */
    private onLoad() {
        this.complete();
    }
}

export default ImageResource;